afterHooks.code:
const results = global.__e2eResults || [];
logger.info('\n═══════════════════════════════════════════════════════════════════════');
logger.info('  📊  ALL SUITES COMPLETE — GENERATING REPORTS                       ');
logger.info('═══════════════════════════════════════════════════════════════════════');
const passed  = results.filter(r => r.status === 'passed').length;
const failed  = results.filter(r => r.status === 'failed').length;
const total   = results.length;
const rate    = total > 0 ? ((passed / total) * 100).toFixed(1) : '0.0';
logger.info(`  Total: ${total} | ✅ Passed: ${passed} | ❌ Failed: ${failed} | 📈 Rate: ${rate}%`);
try {
  await generateReport(results, {
    browser: config.browser.default,
    environment: process.env.NODE_ENV || 'local',
    baseUrl: config.baseUrl,
  });
} catch (err) {
  logger.error(`Failed to generate Excel report: ${err.message}`);
}
logger.info('\n  Reports saved to: ./reports/');
logger.info('═══════════════════════════════════════════════════════════════════════\n');

beforeHooks.code:
logger.suiteStart('Comprehensive Master Suite');
driver = await DriverFactory.create();
loginPage = new LoginPage(driver);
screenshotHelper = new ScreenshotHelper(driver);

afterHooks.code:
const test = this.currentTest;
let screenshotPath = null;
if (test.state === 'failed') {
  logger.fail(test.title);
  screenshotPath = await screenshotHelper.captureFailure(test.title).catch(() => null);
} else {
  logger.pass(test.title);
}
results.push({
  suite: 'Master DDT Suite',
  title: test.title,
  status: test.state,
  duration: test.duration || 0,
  err: test.err || null,
  screenshotPath,
});

